void solve(int CASE)
{
	ll n, p; cin >> n >> p;
	var a = vector<ll>(n + 1);
	var b = vector<pll>();
	fa(i, 1, n)cin >> a[i], b.pb({ a[i],i });
	sort(all(b));

	var s = vector<int>(n + 1);
	fa(i, 1, n)s[i] = i;
	var find = [&](var find, int x)->int {
		if (s[x] == x)return x;
		return s[x] = find(find, s[x]);
		};

	ll ans = 0, cnt = n - 1;
	for (const var& [w, id] : b) {
		if (w > p or cnt == 0)break;
		int e1 = find(find, id);

		fa(i, id + 1, n) {
			if (a[i] % w != 0)break;
			int e2 = find(find, i);
			if (e1 != e2) {
				s[e2] = e1;
				ans += w;
				cnt--;
				if (cnt == 0)break;
			}
			else break;
		}

		fb(i, id - 1, 1) {
			if (a[i] % w != 0)break;
			int e2 = find(find, i);
			if (e1 != e2) {
				s[e2] = e1;
				ans += w;
				cnt--;
				if (cnt == 0)break;
			}
			else break;
		}
	}

	cout << ans + cnt * p << endl;
	return;
}
